#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10,mod=1e9+7;

int n,m,c[N],res=1;

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        scanf("%d",&c[i]);
        n-=c[i];
    }
    for(int i=n-1;i>n-m;i--)
        res=1ll*res*i%mod;
    for(int i=m-1;i;i--)
        res=1ll*res*qpow(i,mod-2)%mod;
    printf("%d",res);
    return 0;
}
